CREATE INDEX `idx_cluster_merge_suggestions_cluster_b` ON `cluster_merge_suggestions` (`cluster_b_id`);
CREATE INDEX `idx_entity_links_created_by` ON `entity_links` (`created_by`);
CREATE INDEX `idx_failure_clusters_project_status` ON `failure_clusters` (`project_id`,`status`);
CREATE INDEX `idx_fdv_test_runs_case` ON `failure_diagnosis_versions` (`test_runs_case_id`);
CREATE INDEX `idx_files_blob_id` ON `files` (`blob_id`);
